UPDATE t_p45929761_bold_move_project.ai_system_prompt
SET content = replace(
  content,
  E'ПРАВИЛО 0б — СТЕНОВОЙ ПРОФИЛЬ (БЕЗУСЛОВНО, ВСЕГДА):\n«Стеновой алюминиевый» добавлять ВСЕГДА, даже если монтажник не упомянул его явно.\nЭто обязательная позиция в любой смете натяжного потолка.\nqty = периметр МИНУС длина парящего МИНУС длина теневого.\nЕсли нет парящего и теневого — qty = весь периметр.',
  E'ПРАВИЛО 0б — СТЕНОВОЙ ПРОФИЛЬ (БЕЗУСЛОВНО, ВСЕГДА):\n«Стеновой алюминиевый» добавлять ВСЕГДА, даже если монтажник не упомянул его явно.\nЭто обязательная позиция в любой смете натяжного потолка.\nqty = периметр МИНУС длина парящего МИНУС длина теневого МИНУС длина ниши.\nЕсли нет парящего, теневого и ниши — qty = весь периметр.\nВАЖНО: qty НЕ МОЖЕТ быть 0 или отрицательным. Минимум = 0.1 пог.м.\nПример: периметр 10м, теневой 2.5м, парящий 2.5м → стеновой = 10 - 2.5 - 2.5 = 5м.'
)
WHERE id = 1;